using System;
using System.Collections.Generic;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_WhenBothNamesSet_ReturnsLastCommaFirst()
    {
        // Arrange – use a concrete subclass because Person is abstract
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        // Act
        var fullName = student.FullName;

        // Assert
        Assert.AreEqual("Smith, John", fullName);
    }

    [TestMethod]
    [DataRow("O'Brien", "Mary", "O'Brien, Mary", DisplayName = "Apostrophe in name")]
    [DataRow("Li", "X", "Li, X", DisplayName = "Short names")]
    public void FullName_VariousNames_FormatsCorrectly(string last, string first, string expected)
    {
        var person = new Instructor { LastName = last, FirstMidName = first, HireDate = DateTime.Today };
        Assert.AreEqual(expected, person.FullName);
    }
}

[TestClass]
public sealed class StudentTests
{
    [TestMethod]
    public void Student_DefaultConstruction_HasNullEnrollments()
    {
        var student = new Student();
        Assert.IsNull(student.Enrollments);
    }

    [TestMethod]
    public void Student_SetProperties_RoundTripsCorrectly()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student
        {
            ID = 42,
            LastName = "Doe",
            FirstMidName = "Jane",
            EnrollmentDate = date
        };

        Assert.AreEqual(42, student.ID);
        Assert.AreEqual("Doe", student.LastName);
        Assert.AreEqual("Jane", student.FirstMidName);
        Assert.AreEqual(date, student.EnrollmentDate);
    }

    [TestMethod]
    public void Student_InheritsFromPerson_FullNameWorks()
    {
        var student = new Student { LastName = "Doe", FirstMidName = "Jane" };
        Assert.AreEqual("Doe, Jane", student.FullName);
    }

    [TestMethod]
    public void Student_EnrollmentsCollection_CanBeAssigned()
    {
        var student = new Student();
        var enrollments = new List<Enrollment> { new Enrollment { EnrollmentID = 1 } };
        student.Enrollments = enrollments;

        Assert.AreEqual(1, student.Enrollments.Count);
    }
}

[TestClass]
public sealed class InstructorTests
{
    [TestMethod]
    public void Instructor_SetProperties_RoundTripsCorrectly()
    {
        var hireDate = new DateTime(2000, 1, 15);
        var instructor = new Instructor
        {
            ID = 10,
            LastName = "Harui",
            FirstMidName = "Roger",
            HireDate = hireDate
        };

        Assert.AreEqual(10, instructor.ID);
        Assert.AreEqual("Harui", instructor.LastName);
        Assert.AreEqual("Roger", instructor.FirstMidName);
        Assert.AreEqual(hireDate, instructor.HireDate);
    }

    [TestMethod]
    public void Instructor_InheritsFromPerson_FullNameWorks()
    {
        var instructor = new Instructor { LastName = "Kapoor", FirstMidName = "Candace" };
        Assert.AreEqual("Kapoor, Candace", instructor.FullName);
    }

    [TestMethod]
    public void Instructor_NavigationProperties_DefaultToNull()
    {
        var instructor = new Instructor();
        Assert.IsNull(instructor.CourseAssignments);
        Assert.IsNull(instructor.OfficeAssignment);
    }
}

[TestClass]
public sealed class CourseTests
{
    [TestMethod]
    public void Course_SetProperties_RoundTripsCorrectly()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/uploads/test.jpg"
        };

        Assert.AreEqual(1050, course.CourseID);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/uploads/test.jpg", course.TeachingMaterialImagePath);
    }

    [TestMethod]
    public void Course_NavigationProperties_DefaultToNull()
    {
        var course = new Course();
        Assert.IsNull(course.Department);
        Assert.IsNull(course.Enrollments);
        Assert.IsNull(course.CourseAssignments);
    }
}

[TestClass]
public sealed class DepartmentTests
{
    [TestMethod]
