using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    private IQueryable<int> CreateSource(int count)
    {
        return Enumerable.Range(1, count).AsQueryable();
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstPageItems()
    {
        // Arrange
        var source = CreateSource(25);

        // Act
        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        // Assert
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(10, result[9]);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(20, result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly_ExactDivision()
    {
        var source = CreateSource(30);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_CalculatedCorrectly_WithRemainder()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.AreEqual(3, result.TotalPages);
    }

    [TestMethod]
    public void TotalPages_SinglePage_Returns1()
    {
        var source = CreateSource(5);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.AreEqual(1, result.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_FirstPageOfMany_ReturnsTrue()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        var source = CreateSource(5);

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void PageIndex_IsSetCorrectly()
    {
        var source = CreateSource(25);

        var result = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 10);

        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Constructor_EmptyItems_CreatesEmptyList()
    {
        var result = new PaginatedList<int>(new List<int>(), count: 0, pageIndex: 1, pageSize: 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }
}

using System;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void TestInitialize()
    {
        // Drain any leftover notifications from other tests
        TestHelper.DrainNotificationQueue();
        _sut = new NotificationService();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();
        // Drain again to clean up after this test
        TestHelper.DrainNotificationQueue();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesCorrectNotification()
    {
        // Act
        _sut.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_GeneratesCorrectCreateMessage()
    {
        _sut.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_GeneratesCorrectUpdateMessage()
    {
        _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_GeneratesCorrectDeleteMessage()
    {
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
    {
        _sut.SendNotification("Instructor", "10", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("New Instructor (ID: 10) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_GeneratesIdBasedMessage()
    {
        _sut.SendNotification("Student", "42", null, EntityOperation.UPDATE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Student (ID: 42) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_GeneratesIdBasedMessage()
    {
        _sut.SendNotification("Student", "42", "   ", EntityOperation.DELETE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("Student (ID: 42) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DefaultUserName_SetsSystemUser()
    {
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        var notification = _sut.ReceiveNotification();
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        var notification = _sut.ReceiveNotification();
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void SendAndReceive_MultipleNotifications_FIFOOrder()
    {
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);
        _sut.SendNotification("C", "3", EntityOperation.DELETE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();
        var third = _sut.ReceiveNotification();

        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("B", second.EntityType);
        Assert.AreEqual("C", third.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_AfterAllDequeued_ReturnsNull()
    {
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
        _sut.ReceiveNotification(); // consume it

        var result = _sut.ReceiveNotification();
        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_CreatedAt_IsSetToRecentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _sut.ReceiveNotification();
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        // No exception = pass
    }

    [TestMethod]
    public void Dispose_CalledMultipleTimes_DoesNotThrow()
    {
        _sut.Dispose();
        _sut.Dispose();
        // No exception = pass
    }
}

