using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _sut;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _sut = new HomeController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();
        _context?.Dispose();
        TestHelper.DrainNotificationQueue();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _sut.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Contact_ReturnsViewResult()
    {
        var result = _sut.Contact();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.AreEqual("Your contact page.", _sut.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        var result = _sut.Error();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewWithMessage()
    {
        var result = _sut.Unauthorized();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.AreEqual("You don't have permission to access this resource.", _sut.ViewBag.Message);
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        var result = _sut.About();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsGroupedEnrollmentData()
    {
        // Arrange
        var date1 = new DateTime(2023, 9, 1);
        var date2 = new DateTime(2024, 1, 15);
        _context.Students.AddRange(
            new Student { LastName = "A", FirstMidName = "S1", EnrollmentDate = date1 },
            new Student { LastName = "B", FirstMidName = "S2", EnrollmentDate = date1 },
            new Student { LastName = "C", FirstMidName = "S3", EnrollmentDate = date2 }
        );
        _context.SaveChanges();

        // Act
        var result = _sut.About();

        // Assert
        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group1 = model.Single(g => g.EnrollmentDate == date1);
        Assert.AreEqual(2, group1.StudentCount);

        var group2 = model.Single(g => g.EnrollmentDate == date2);
        Assert.AreEqual(1, group2.StudentCount);
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context;
    private StudentsController _sut;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _sut = new StudentsController(_context);
        _sut.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();
        _context?.Dispose();
        TestHelper.DrainNotificationQueue();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2010, 9, 1) },
            new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = new DateTime(2013, 9, 1) },
            new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2012, 9, 1) }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithAllStudents()
    {
        SeedStudents();

        var result = _sut.Index(null, null, null, null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(4, model.Count);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        SeedStudents();

        var result = _sut.Index(null, null, null, null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
        Assert.AreEqual("Barzdukas", model[3].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        SeedStudents();

        var result = _sut.Index("name_desc", null, null, null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual("Barzdukas", model[0].LastName);
        Assert.AreEqual("Alexander", model[3].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        SeedStudents();

        var result = _sut.Index("Date", null, null, null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual("Alexander", model[0].LastName); // 2010
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        SeedStudents();

        var result = _sut.Index("date_desc", null, null, null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual("Anand", model[0].LastName); // 2013
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByLastName()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "Alexander", null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByFirstName()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "Meredith", null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchStringProvided_ResetsPageTo1()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "A", null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchWithCurrentFilter_UsesCurrentFilter()
    {
        SeedStudents();

        var result = _sut.Index(null, "Alexander", null, null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParms()
    {
        SeedStudents();

        _sut.Index(null, null, null, null);

        Assert.AreEqual("name_desc", _sut.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _sut.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_NameDescSort_FlipsNameSortParm()
    {
        SeedStudents();

        _sut.Index("name_desc", null, null, null);

        Assert.AreEqual("", _sut.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_DateSort_FlipsDateSortParm()
    {
        SeedStudents();

        _sut.Index("Date", null, null, null);

        Assert.AreEqual("date_desc", _sut.ViewBag.DateSortParm);
    }

    // --- Details ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        SeedStudents();
        var student = _context.Students.First();
        // Need to add enrollments for Include to work
        _context.Entry(student).Collection(s => s.Enrollments).Load();

        var result = _sut.Details(student.ID);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    // --- Create GET ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _sut.Create();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST ---

    [TestMethod]
    public void Create_Post_ValidStudent_SavesAndRedirects()
    {
        var student = new Student
        {
            LastName = "TestLast",
            FirstMidName = "TestFirst",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _sut.Create(student);

        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);

        // Verify saved
        Assert.AreEqual(1, _context.Students.Count());
        var saved = _context.Students.First();
        Assert.AreEqual("TestLast", saved.LastName);
        Assert.AreEqual("TestFirst", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _sut.Create(student);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBefore1753_AddsModelError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _sut.Create(student);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _sut.ModelState.AddModelError("LastName", "Required");
        var student = new Student { EnrollmentDate = new DateTime(2023, 9, 1) };

        var result = _sut.Create(student);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.AreEqual(0, _context.Students.Count());
    }

    // --- Edit GET ---

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Edit(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        SeedStudents();
        var student = _context.Students.First();

        var result = _sut.Edit(student.ID);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    // --- Edit POST ---

    [TestMethod]
    public void Edit_Post_ValidStudent_SavesAndRedirects()
    {
        SeedStudents();
        var student = _context.Students.First();
        // Detach so we can attach the edited version
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var editedStudent = new Student
        {
            ID = student.ID,
            LastName = "UpdatedLast",
            FirstMidName = "UpdatedFirst",
            EnrollmentDate = new DateTime(2024, 1, 1)
        };

        var result = _sut.Edit(editedStudent);

        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Edit_Post_MinValueDate_AddsModelError()
    {
        SeedStudents();
        var student = _context.Students.First();

        var editedStudent = new Student
        {
            ID = student.ID,
            LastName = "Test",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _sut.Edit(editedStudent);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    // --- Delete GET ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
