using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context;
    private DepartmentsController _sut;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _sut = new DepartmentsController(_context);
        _sut.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();
        _context?.Dispose();
        TestHelper.DrainNotificationQueue();
    }

    private void SeedDepartments()
    {
        var instructor = new Instructor
        {
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = new DateTime(1995, 3, 11)
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.Departments.AddRange(
            new Department { Name = "English", Budget = 350000, StartDate = new DateTime(2007, 9, 1), InstructorID = instructor.ID },
            new Department { Name = "Mathematics", Budget = 100000, StartDate = new DateTime(2007, 9, 1) },
            new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2007, 9, 1) }
        );
        _context.SaveChanges();
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        SeedDepartments();

        var result = _sut.Index();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    // --- Details ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Details(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartments();
        var dept = _context.Departments.First();

        var result = _sut.Details(dept.DepartmentID);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
        Assert.AreEqual(dept.Name, model.Name);
    }

    // --- Create GET ---

    [TestMethod]
    public void Create_Get_ReturnsViewResult()
    {
        SeedDepartments();

        var result = _sut.Create();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    // --- Create POST ---

    [TestMethod]
    public void Create_Post_ValidDepartment_SavesAndRedirects()
    {
        SeedDepartments();
        var department = new Department
        {
            Name = "Economics",
            Budget = 100000,
            StartDate = new DateTime(2007, 9, 1)
        };

        var result = _sut.Create(department);

        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);

        Assert.AreEqual(4, _context.Departments.Count());
        var saved = _context.Departments.Single(d => d.Name == "Economics");
        Assert.AreEqual(100000, saved.Budget);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        SeedDepartments();
        _sut.ModelState.AddModelError("Name", "Required");
        var department = new Department { Budget = 100000 };

        var result = _sut.Create(department);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
    }

    // --- Edit GET ---

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Edit(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartments();
        var dept = _context.Departments.First();

        var result = _sut.Edit(dept.DepartmentID);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
    }

    // --- Edit POST ---

    [TestMethod]
    public void Edit_Post_ValidDepartment_SavesAndRedirects()
    {
        SeedDepartments();
        var dept = _context.Departments.First();
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var editedDept = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated Name",
            Budget = 500000,
            StartDate = new DateTime(2020, 1, 1)
        };

        var result = _sut.Edit(editedDept);

        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        SeedDepartments();
        _sut.ModelState.AddModelError("Name", "Required");
        var dept = new Department { DepartmentID = 1 };

        var result = _sut.Edit(dept);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
    }

    // --- Delete GET ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Delete(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        SeedDepartments();
        var dept = _context.Departments.First();

        var result = _sut.Delete(dept.DepartmentID);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual(dept.DepartmentID, model.DepartmentID);
    }

    // --- DeleteConfirmed ---

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
    {
        SeedDepartments();
        var dept = _context.Departments.First();
        var initialCount = _context.Departments.Count();

        var result = _sut.DeleteConfirmed(dept.DepartmentID);

        var redirectResult = result as RedirectToActionResult;
        Assert.IsNotNull(redirectResult);
        Assert.AreEqual("Index", redirectResult.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Departments.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentFromDatabase()
    {
        SeedDepartments();
        var dept = _context.Departments.Single(d => d.Name == "Mathematics");

        _sut.DeleteConfirmed(dept.DepartmentID);

        Assert.IsNull(_context.Departments.Find(dept.DepartmentID));
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
