namespace ContosoUniversity.Tests;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context;
    private CoursesController _sut;
    private Mock<IWebHostEnvironment> _mockEnv;
    private Mock<ILogger<CoursesController>> _mockLogger;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.ContentRootPath).Returns("/app");
        _mockEnv.Setup(e => e.WebRootPath).Returns((string)null);
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _sut = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        _sut.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();
        _context?.Dispose();
        TestHelper.DrainNotificationQueue();
    }

    private Department SeedDepartmentAndCourses()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = dept.DepartmentID }
        );
        _context.SaveChanges();
        return dept;
    }

    // --- Index ---

    [TestMethod]
    public void Index_ReturnsViewWithCourses()
    {
        SeedDepartmentAndCourses();

        var result = _sut.Index();

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Index_IncludesDepartmentData()
    {
        SeedDepartmentAndCourses();

        var result = _sut.Index();

        var viewResult = result as ViewResult;
        var model = viewResult.Model as List<Course>;
        Assert.IsTrue(model.All(c => c.Department != null));
        Assert.AreEqual("Engineering", model[0].Department.Name);
    }

    // --- Details ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
    }

    [TestMethod]
