        SeedDepartmentAndCourses();

        var result = _sut.Details(1050);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual(1050, model.CourseID);
        Assert.AreEqual("Chemistry", model.Title);
    }

    [TestMethod]
    public void Details_ValidId_IncludesDepartment()
