    [TestMethod]
    public void Create_Post_InvalidFileExtension_AddsModelError()
    {
        SeedDepartmentAndCourses();
        var dept = _context.Departments.First();
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.exe");
        mockFile.Setup(f => f.Length).Returns(1024);

        var result = _sut.Create(course, mockFile.Object);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        var errors = _sut.ModelState["teachingMaterialImage"].Errors;
        Assert.IsTrue(errors.Any(e => e.ErrorMessage.Contains("valid image file")));
    }

    [TestMethod]
    public void Create_Post_FileTooLarge_AddsModelError()
    {
        SeedDepartmentAndCourses();
        var dept = _context.Departments.First();
        var course = new Course { CourseID = 9999, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("test.jpg");
        mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB, over limit

        var result = _sut.Create(course, mockFile.Object);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        var errors = _sut.ModelState["teachingMaterialImage"].Errors;
        Assert.IsTrue(errors.Any(e => e.ErrorMessage.Contains("5MB")));
    }

    [TestMethod]
