using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _sut;

    [TestInitialize]
    public void TestInitialize()
    {
        TestHelper.DrainNotificationQueue();
        _context = TestHelper.CreateInMemoryContext();
        _sut = new InstructorsController(_context);
        _sut.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut?.Dispose();
        _context?.Dispose();
        TestHelper.DrainNotificationQueue();
    }

    private void SeedInstructorsWithCoursesAndDepartments()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 350000,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID };
        var course2 = new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = dept.DepartmentID };
        _context.Courses.AddRange(course1, course2);
        _context.SaveChanges();

        var instructor1 = new Instructor
        {
            LastName = "Harui",
            FirstMidName = "Roger",
            HireDate = new DateTime(1998, 7, 1),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Gowan 27" }
        };
        var instructor2 = new Instructor
        {
            LastName = "Kapoor",
            FirstMidName = "Candace",
            HireDate = new DateTime(2001, 1, 15),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.AddRange(instructor1, instructor2);
        _context.SaveChanges();

        _context.CourseAssignments.Add(new CourseAssignment { CourseID = 1050, InstructorID = instructor1.ID });
        _context.CourseAssignments.Add(new CourseAssignment { CourseID = 1045, InstructorID = instructor2.ID });
        _context.SaveChanges();
    }

    // --- Index ---

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        SeedInstructorsWithCoursesAndDepartments();

        var result = _sut.Index(null, null);

        var viewResult = result as ViewResult;
        Assert.IsNotNull(viewResult);
        var model = viewResult.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_InstructorsOrderedByLastName()
    {
        SeedInstructorsWithCoursesAndDepartments();

        var result = _sut.Index(null, null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as InstructorIndexData;
        var instructors = model.Instructors.ToList();
        Assert.AreEqual("Harui", instructors[0].LastName);
        Assert.AreEqual("Kapoor", instructors[1].LastName);
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsCourses()
    {
        SeedInstructorsWithCoursesAndDepartments();
        var instructor = _context.Instructors.First(i => i.LastName == "Harui");

        var result = _sut.Index(instructor.ID, null);

        var viewResult = result as ViewResult;
        var model = viewResult.Model as InstructorIndexData;
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Chemistry", model.Courses.First().Title);
    }

    // --- Details ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        var statusResult = result as StatusCodeResult;
        Assert.IsNotNull(statusResult);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
