        DbInitializer.Initialize(context);

        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_ExistingStudents_DoesNotReseed()
    {
        using var context = TestHelper.CreateInMemoryContext();
        // Pre-seed one student
        context.Students.Add(new Student
        {
            LastName = "Existing",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2023, 1, 1)
        });
        context.SaveChanges();

        DbInitializer.Initialize(context);

        // Should still have just the one we added
        Assert.AreEqual(1, context.Students.Count());
        Assert.AreEqual("Existing", context.Students.First().LastName);
    }

    [TestMethod]
    public void Initialize_SeededStudents_HaveCorrectData()
    {
        using var context = TestHelper.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var carson = context.Students.Single(s => s.LastName == "Alexander");
        Assert.AreEqual("Carson", carson.FirstMidName);
        Assert.AreEqual(new DateTime(2010, 9, 1), carson.EnrollmentDate);
    }

    [TestMethod]
    public void Initialize_SeededInstructors_HaveCorrectData()
    {
        using var context = TestHelper.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var kim = context.Instructors.Single(i => i.LastName == "Abercrombie");
        Assert.AreEqual("Kim", kim.FirstMidName);
        Assert.AreEqual(new DateTime(1995, 3, 11), kim.HireDate);
    }

    [TestMethod]
    public void Initialize_SeededDepartments_HaveCorrectBudgets()
    {
        using var context = TestHelper.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var english = context.Departments.Single(d => d.Name == "English");
        Assert.AreEqual(350000, english.Budget);

        var math = context.Departments.Single(d => d.Name == "Mathematics");
        Assert.AreEqual(100000, math.Budget);
    }

    [TestMethod]
    public void Initialize_SeededCourses_HaveCorrectCredits()
    {
        using var context = TestHelper.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        Assert.AreEqual(3, chemistry.Credits);
        Assert.AreEqual(1050, chemistry.CourseID);

        var calculus = context.Courses.Single(c => c.Title == "Calculus");
        Assert.AreEqual(4, calculus.Credits);
        Assert.AreEqual(1045, calculus.CourseID);
    }

    [TestMethod]
    public void Initialize_SeededEnrollments_HaveCorrectGrades()
    {
        using var context = TestHelper.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var alexander = context.Students.Single(s => s.LastName == "Alexander");
        var chemistryEnrollment = context.Enrollments
            .Single(e => e.StudentID == alexander.ID && e.CourseID == 1050);
        Assert.AreEqual(Grade.A, chemistryEnrollment.Grade);
    }

    [TestMethod]
    public void Initialize_SeededEnrollments_SomeHaveNullGrade()
    {
        using var context = TestHelper.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var anand = context.Students.Single(s => s.LastName == "Anand");
        var chemistryEnrollment = context.Enrollments
            .Single(e => e.StudentID == anand.ID && e.CourseID == 1050);
        Assert.IsNull(chemistryEnrollment.Grade);
    }
}

