    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        using var context = TestHelper.CreateInMemoryContext();
        var student = new Student
        {
            LastName = "Doe",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.Single();
        Assert.AreEqual("Doe", retrieved.LastName);
        Assert.AreEqual("John", retrieved.FirstMidName);
        Assert.AreEqual(new DateTime(2023, 9, 1), retrieved.EnrollmentDate);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveInstructor()
    {
        using var context = TestHelper.CreateInMemoryContext();
        var instructor = new Instructor
        {
            LastName = "Smith",
            FirstMidName = "Jane",
            HireDate = new DateTime(2020, 1, 15)
        };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.Single();
        Assert.AreEqual("Smith", retrieved.LastName);
        Assert.AreEqual(new DateTime(2020, 1, 15), retrieved.HireDate);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        using var context = TestHelper.CreateInMemoryContext();

        // Add prerequisites
        var instructor = new Instructor { LastName = "Test", FirstMidName = "I", HireDate = DateTime.Today };
        context.Instructors.Add(instructor);
        var dept = new Department { Name = "TestDept", Budget = 1000, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 100, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment { CourseID = 100, InstructorID = instructor.ID };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        var retrieved = context.CourseAssignments.Single();
        Assert.AreEqual(100, retrieved.CourseID);
        Assert.AreEqual(instructor.ID, retrieved.InstructorID);
    }

    [TestMethod]
    public void SchoolContext_InstructorOfficeAssignment_OneToOne()
    {
        using var context = TestHelper.CreateInMemoryContext();
        var instructor = new Instructor
        {
            LastName = "Test",
            FirstMidName = "I",
            HireDate = DateTime.Today,
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.Include(i => i.OfficeAssignment).Single();
        Assert.IsNotNull(retrieved.OfficeAssignment);
        Assert.AreEqual("Room 101", retrieved.OfficeAssignment.Location);
    }

    [TestMethod]
    public void SchoolContext_CourseEnrollments_Relationship()
    {
        using var context = TestHelper.CreateInMemoryContext();

        var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Today };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 200, Title = "Test Course", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);

        var student = new Student { LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Today };
        context.Students.Add(student);
        context.SaveChanges();

        var enrollment = new Enrollment { CourseID = 200, StudentID = student.ID, Grade = Grade.B };
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        var retrieved = context.Enrollments.Single();
        Assert.AreEqual(200, retrieved.CourseID);
        Assert.AreEqual(student.ID, retrieved.StudentID);
        Assert.AreEqual(Grade.B, retrieved.Grade);
    }
}

